    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0-or-later\n/*\n * Copyright 2013 Red Hat Inc.\n *\n * Authors: Jérôme Glisse <jglisse@redhat.com>\n */\n/*\n * Refer to include/linux/hmm.h for information about heterogeneous memory\n * management or HMM for short.\n */\n#include <linux/pagewalk.h>\n#include <linux/hmm.h>\n#include <linux/hmm-dma.h>\n#include <linux/init.h>\n#include <linux/rmap.h>\n#include <linux/swap.h>\n#include <linux/slab.h>\n#include <linux/sched.h>\n#include <linux/mmzone.h>\n#include <linux/pagemap.h>\n#include <linux/leafops.h>\n#include <linux/hugetlb.h>\n#include <linux/memremap.h>\n#include <linux/sched/mm.h>\n#include <linux/jump_label.h>\n#include <linux/dma-mapping.h>\n#include <linux/pci-p2pdma.h>\n#include <linux/mmu_notifier.h>\n#include <linux/memory_hotplug.h>\n\n#include \"internal.h\"\n\nstruct hmm_vma_walk {\n\tstruct hmm_range\t*range;\n\tunsigned long\t\tlast;\n};\n\nenum {\n\tHMM_NEED_FAULT = 1 << 0,\n\tHMM_NEED_WRITE_FAULT = 1 << 1,\n\tHMM_NEED_ALL_BITS = HMM_NEED_FAULT | HMM_NEED_WRITE_FAULT,\n};\n\nenum {\n\t/* These flags are carried from input-to-output */\n\tHMM_PFN_INOUT_FLAGS = HMM_PFN_DMA_MAPPED | HMM_PFN_P2PDMA |\n\t\t\t      HMM_PFN_P2PDMA_BUS,\n};\n\nstatic int hmm_pfns_fill(unsigned long addr, unsigned long end,\n\t\t\t struct hmm_range *range, unsigned long cpu_flags)\n{\n\tunsigned long i = (addr - range->start) >> PAGE_SHIFT;\n\n\tfor (; addr < end; addr += PAGE_SIZE, i++) {\n\t\trange->hmm_pfns[i] &= HMM_PFN_INOUT_FLAGS;\n\t\trange->hmm_pfns[i] |= cpu_flags;\n\t}\n\treturn 0;\n}\n\n/*\n * hmm_vma_fault() - fault in a range lacking valid pmd or pte(s)\n * @addr: range virtual start address (inclusive)\n * @end: range virtual end address (exclusive)\n * @required_fault: HMM_NEED_* flags\n * @walk: mm_walk structure\n * Return: -EBUSY after page fault, or page fault error\n *\n * This function will be called whenever pmd_none() or pte_none() returns true,\n * or whenever there is no page directory covering the virtual address range.\n */\nstatic int hmm_vma_fault(unsigned long addr, unsigned long end,\n\t\t\t unsigned int required_fault, struct mm_walk *walk)\n{\n\tstruct hmm_vma_walk *hmm_vma_walk = walk->private;\n\tstruct vm_area_struct *vma = walk->vma;\n\tunsigned int fault_flags = FAULT_FLAG_REMOTE;\n\n\tWARN_ON_ONCE(!required_fault);\n\thmm_vma_walk->last = addr;\n\n\tif (required_fault & HMM_NEED_WRITE_FAULT) {\n\t\tif (!(vma->vm_flags & VM_WRITE))\n\t\t\treturn -EPERM;\n\t\tfault_flags |= FAULT_FLAG_WRITE;\n\t}\n\n\tfor (; addr < end; addr += PAGE_SIZE)\n\t\tif (handle_mm_fault(vma, addr, fault_flags, NULL) &\n\t\t    VM_FAULT_ERROR)\n\t\t\treturn -EFAULT;\n\treturn -EBUSY;\n}\n\nstatic unsigned int hmm_pte_need_fault(const struct hmm_vma_walk *hmm_vma_walk,\n\t\t\t\t       unsigned long pfn_req_flags,\n\t\t\t\t       unsigned long cpu_flags)\n{\n\tstruct hmm_range *range = hmm_vma_walk->range;\n\n\t/*\n\t * So we not only consider the individual per page request we also\n\t * consider the default flags requested for the range. The API can\n\t * be used 2 ways. The first one where the HMM user coalesces\n\t * multiple page faults into one request and sets flags per pfn for\n\t * those faults. The second one where the HMM user wants to pre-\n\t * fault a range with specific flags. For the latter one it is a\n\t * waste to have the user pre-fill the pfn arrays with a default\n\t * flags value.\n\t */\n\tpfn_req_flags &= range->pfn_flags_mask;\n\tpfn_req_flags |= range->default_flags;\n\n\t/* We aren't ask to do anything ... */\n\tif (!(pfn_req_flags & HMM_PFN_REQ_FAULT))\n\t\treturn 0;\n\n\t/* Need to write fault ? */\n\tif ((pfn_req_flags & HMM_PFN_REQ_WRITE) &&\n\t    !(cpu_flags & HMM_PFN_WRITE))\n\t\treturn HMM_NEED_FAULT | HMM_NEED_WRITE_FAULT;\n\n\t/* If CPU page table is not valid then we need to fault */\n\tif (!(cpu_flags & HMM_PFN_VALID))\n\t\treturn HMM_NEED_FAULT;\n\treturn 0;\n}\n\nstatic unsigned int\nhmm_range_need_fault(const struct hmm_vma_walk *hmm_vma_walk,\n\t\t     const unsigned long hmm_pfns[], unsigned long npages,\n\t\t     unsigned long cpu_flags)\n{\n\tstruct hmm_range *range = hmm_vma_walk->range;\n\tunsigned int required_fault = 0;\n\tunsigned long i;\n\n\t/*\n\t * If the default flags do not request to fault pages, and the mask does\n\t * not allow for individual pages to be faulted, then\n\t * hmm_pte_need_fault() will always return 0.\n\t */\n\tif (!((range->default_flags | range->pfn_flags_mask) &\n\t      HMM_PFN_REQ_FAULT))\n\t\treturn 0;\n\n\tfor (i = 0; i < npages; ++i) {\n\t\trequired_fault |= hmm_pte_need_fault(hmm_vma_walk, hmm_pfns[i],\n\t\t\t\t\t\t     cpu_flags);\n\t\tif (required_fault == HMM_NEED_ALL_BITS)\n\t\t\treturn required_fault;\n\t}\n\treturn required_fault;\n}\n\nstatic int hmm_vma_walk_hole(unsigned long addr, unsigned long end,\n\t\t\t     __always_unused int depth, struct mm_walk *walk)\n{\n\tstruct hmm_vma_walk *hmm_vma_walk = walk->private;\n\tstruct hmm_range *range = hmm_vma_walk->range;\n\tunsigned int required_fault;\n\tunsigned long i, npages;\n\tunsigned long *hmm_pfns;\n\n\ti = (addr - range->start) >> PAGE_SHIFT;\n\tnpages = (end - addr) >> PAGE_SHIFT;\n\thmm_pfns = &range->hmm_pfns[i];\n\trequired_fault =\n\t\thmm_range_need_fault(hmm_vma_walk, hmm_pfns, npages, 0);\n\tif (!walk->vma) {\n\t\tif (required_fault)\n\t\t\treturn -EFAULT;\n\t\treturn hmm_pfns_fill(addr, end, range, HMM_PFN_ERROR);\n\t}\n\tif (required_fault)\n\t\treturn hmm_vma_fault(addr, end, required_fault, walk);\n\treturn hmm_pfns_fill(addr, end, range, 0);\n}\n\nstatic inline unsigned long hmm_pfn_flags_order(unsigned long order)\n{\n\treturn order << HMM_PFN_ORDER_SHIFT;\n}\n\n#ifdef CONFIG_TRANSPARENT_HUGEPAGE\nstatic inline unsigned long pmd_to_hmm_pfn_flags(struct hmm_range *range,\n\t\t\t\t\t\t pmd_t pmd)\n{\n\tif (pmd_protnone(pmd))\n\t\treturn 0;\n\treturn (pmd_write(pmd) ? (HMM_PFN_VALID | HMM_PFN_WRITE) :\n\t\t\t\t HMM_PFN_VALID) |\n\t       hmm_pfn_flags_order(PMD_SHIFT - PAGE_SHIFT);\n}\n\nstatic int hmm_vma_handle_pmd(struct mm_walk *walk, unsigned long addr,\n\t\t\t      unsigned long end, unsigned long hmm_pfns[],\n\t\t\t      pmd_t pmd)\n{\n\tstruct hmm_vma_walk *hmm_vma_walk = walk->private;\n\tstruct hmm_range *range = hmm_vma_walk->range;\n\tunsigned long pfn, npages, i;\n\tunsigned int required_fault;\n\tunsigned long cpu_flags;\n\n\tnpages = (end - addr) >> PAGE_SHIFT;\n\tcpu_flags = pmd_to_hmm_pfn_flags(range, pmd);\n\trequired_fault =\n\t\thmm_range_need_fault(hmm_vma_walk, hmm_pfns, npages, cpu_flags);\n\tif (required_fault)\n\t\treturn hmm_vma_fault(addr, end, required_fault, walk);\n\n\tpfn = pmd_pfn(pmd) + ((addr & ~PMD_MASK) >> PAGE_SHIFT);\n\tfor (i = 0; addr < end; addr += PAGE_SIZE, i++, pfn++) {\n\t\thmm_pfns[i] &= HMM_PFN_INOUT_FLAGS;\n\t\thmm_pfns[i] |= pfn | cpu_flags;\n\t}\n\treturn 0;\n}\n#else /* CONFIG_TRANSPARENT_HUGEPAGE */\n/* stub to allow the code below to compile */\nint hmm_vma_handle_pmd(struct mm_walk *walk, unsigned long addr,\n\t\tunsigned long end, unsigned long hmm_pfns[], pmd_t pmd);\n#endif /* CONFIG_TRANSPARENT_HUGEPAGE */\n\nstatic inline unsigned long pte_to_hmm_pfn_flags(struct hmm_range *range,\n\t\t\t\t\t\t pte_t pte)\n{\n\tif (pte_none(pte) || !pte_present(pte) || pte_protnone(pte))\n\t\treturn 0;\n\treturn pte_write(pte) ? (HMM_PFN_VALID | HMM_PFN_WRITE) : HMM_PFN_VALID;\n}\n\nstatic int hmm_vma_handle_pte(struct mm_walk *walk, unsigned long addr,\n\t\t\t      unsigned long end, pmd_t *pmdp, pte_t *ptep,\n\t\t\t      unsigned long *hmm_pfn)\n{\n\tstruct hmm_vma_walk *hmm_vma_walk = walk->private;\n\tstruct hmm_range *range = hmm_vma_walk->range;\n\tunsigned int required_fault;\n\tunsigned long cpu_flags;\n\tpte_t pte = ptep_get(ptep);\n\tuint64_t pfn_req_flags = *hmm_pfn;\n\tuint64_t new_pfn_flags = 0;\n\n\t/*\n\t * Any other marker than a UFFD WP marker will result in a fault error\n\t * that will be correctly handled, so we need only check for UFFD WP\n\t * here.\n\t */\n\tif (pte_none(pte) || pte_is_uffd_wp_marker(pte)) {\n\t\trequired_fault =\n\t\t\thmm_pte_need_fault(hmm_vma_walk, pfn_req_flags, 0);\n\t\tif (required_fault)\n\t\t\tgoto fault;\n\t\tgoto out;\n\t}\n\n\tif (!pte_present(pte)) {\n\t\tconst softleaf_t entry = softleaf_from_pte(pte);\n\n\t\t/*\n\t\t * Don't fault in device private pages owned by the caller,\n\t\t * just report the PFN.\n\t\t */\n\t\tif (softleaf_is_device_private(entry) &&\n\t\t    page_pgmap(softleaf_to_page(entry))->owner ==\n\t\t    range->dev_private_owner) {\n\t\t\tcpu_flags = HMM_PFN_VALID;\n\t\t\tif (softleaf_is_device_private_write(entry))\n\t\t\t\tcpu_flags |= HMM_PFN_WRITE;\n\t\t\tnew_pfn_flags = softleaf_to_pfn(entry) | cpu_flags;\n\t\t\tgoto out;\n\t\t}\n\n\t\trequired_fault =\n\t\t\thmm_pte_need_fault(hmm_vma_walk, pfn_req_flags, 0);\n\t\tif (!required_fault)\n\t\t\tgoto out;\n\n\t\tif (softleaf_is_swap(entry))\n\t\t\tgoto fault;\n\n\t\tif (softleaf_is_device_private(entry))\n\t\t\tgoto fault;\n\n\t\tif (softleaf_is_device_exclusive(entry))\n\t\t\tgoto fault;\n\n\t\tif (softleaf_is_migration(entry)) {\n\t\t\tpte_unmap(ptep);\n\t\t\thmm_vma_walk->last = addr;\n\t\t\tmigration_entry_wait(walk->mm, pmdp, addr);\n\t\t\treturn -EBUSY;\n\t\t}\n\n\t\t/* Report error for everything else */\n\t\tpte_unmap(ptep);\n\t\treturn -EFAULT;\n\t}\n\n\tcpu_flags = pte_to_hmm_pfn_flags(range, pte);\n\trequired_fault =\n\t\thmm_pte_need_fault(hmm_vma_walk, pfn_req_flags, cpu_flags);\n\tif (required_fault)\n\t\tgoto fault;\n\n\t/*\n\t * Since each architecture defines a struct page for the zero page, just\n\t * fall through and treat it like a normal page.\n\t */\n\tif (!vm_normal_page(walk->vma, addr, pte) &&\n\t    !is_zero_pfn(pte_pfn(pte))) {\n\t\tif (hmm_pte_need_fault(hmm_vma_walk, pfn_req_flags, 0)) {\n\t\t\tpte_unmap(ptep);\n\t\t\treturn -EFAULT;\n\t\t}\n\t\tnew_pfn_flags = HMM_PFN_ERROR;\n\t\tgoto out;\n\t}\n\n\tnew_pfn_flags = pte_pfn(pte) | cpu_flags;\nout:\n\t*hmm_pfn = (*hmm_pfn & HMM_PFN_INOUT_FLAGS) | new_pfn_flags;\n\treturn 0;\n\nfault:\n\tpte_unmap(ptep);\n\t/* Fault any virtual address we were asked to fault */\n\treturn hmm_vma_fault(addr, end, required_fault, walk);\n}\n\n#ifdef CONFIG_ARCH_ENABLE_THP_MIGRATION\nstatic int hmm_vma_handle_absent_pmd(struct mm_walk *walk, unsigned long start,\n\t\t\t\t     unsigned long end, unsigned long *hmm_pfns,\n\t\t\t\t     pmd_t pmd)\n{\n\tstruct hmm_vma_walk *hmm_vma_walk = walk->private;\n\tstruct hmm_range *range = hmm_vma_walk->range;\n\tunsigned long npages = (end - start) >> PAGE_SHIFT;\n\tconst softleaf_t entry = softleaf_from_pmd(pmd);\n\tunsigned long addr = start;\n\tunsigned int required_fault;\n\n\tif (softleaf_is_device_private(entry) &&\n\t    softleaf_to_folio(entry)->pgmap->owner ==\n\t    range->dev_private_owner) {\n\t\tunsigned long cpu_flags = HMM_PFN_VALID |\n\t\t\thmm_pfn_flags_order(PMD_SHIFT - PAGE_SHIFT);\n\t\tunsigned long pfn = softleaf_to_pfn(entry);\n\t\tunsigned long i;\n\n\t\tif (softleaf_is_device_private_write(entry))\n\t\t\tcpu_flags |= HMM_PFN_WRITE;\n\n\t\t/*\n\t\t * Fully populate the PFN list though subsequent PFNs could be\n\t\t * inferred, because drivers which are not yet aware of large\n\t\t * folios probably do not support sparsely populated PFN lists.\n\t\t */\n\t\tfor (i = 0; addr < end; addr += PAGE_SIZE, i++, pfn++) {\n\t\t\thmm_pfns[i] &= HMM_PFN_INOUT_FLAGS;\n\t\t\thmm_pfns[i] |= pfn | cpu_flags;\n\t\t}\n\n\t\treturn 0;\n\t}\n\n\trequired_fault = hmm_range_need_fault(hmm_vma_walk, hmm_pfns,\n\t\t\t\t\t      npages, 0);\n\tif (required_fault) {\n\t\tif (softleaf_is_device_private(entry))\n\t\t\treturn hmm_vma_fault(addr, end, required_fault, walk);\n\t\telse\n\t\t\treturn -EFAULT;\n\t}\n\n\treturn hmm_pfns_fill(start, end, range, HMM_PFN_ERROR);\n}\n#else\nstatic int hmm_vma_handle_absent_pmd(struct mm_walk *walk, unsigned long start,\n\t\t\t\t     unsigned long end, unsigned long *hmm_pfns,\n\t\t\t\t     pmd_t pmd)\n{\n\tstruct hmm_vma_walk *hmm_vma_walk = walk->private;\n\tstruct hmm_range *range = hmm_vma_walk->range;\n\tunsigned long npages = (end - start) >> PAGE_SHIFT;\n\n\tif (hmm_range_need_fault(hmm_vma_walk, hmm_pfns, npages, 0))\n\t\treturn -EFAULT;\n\treturn hmm_pfns_fill(start, end, range, HMM_PFN_ERROR);\n}\n#endif  /* CONFIG_ARCH_ENABLE_THP_MIGRATION */\n\nstatic int hmm_vma_walk_pmd(pmd_t *pmdp,\n\t\t\t    unsigned long start,\n\t\t\t    unsigned long end,\n\t\t\t    struct mm_walk *walk)\n{\n\tstruct hmm_vma_walk *hmm_vma_walk = walk->private;\n\tstruct hmm_range *range = hmm_vma_walk->range;\n\tunsigned long *hmm_pfns =\n\t\t&range->hmm_pfns[(start - range->start) >> PAGE_SHIFT];\n\tunsigned long npages = (end - start) >> PAGE_SHIFT;\n\tunsigned long addr = start;\n\tpte_t *ptep;\n\tpmd_t pmd;\n\nagain:\n\tpmd = pmdp_get_lockless(pmdp);\n\tif (pmd_none(pmd))\n\t\treturn hmm_vma_walk_hole(start, end, -1, walk);\n\n\tif (thp_migration_supported() && pmd_is_migration_entry(pmd)) {\n\t\tif (hmm_range_need_fault(hmm_vma_walk, hmm_pfns, npages, 0)) {\n\t\t\thmm_vma_walk->last = addr;\n\t\t\tpmd_migration_entry_wait(walk->mm, pmdp);\n\t\t\treturn -EBUSY;\n\t\t}\n\t\treturn hmm_pfns_fill(start, end, range, 0);\n\t}\n\n\tif (!pmd_present(pmd))\n\t\treturn hmm_vma_handle_absent_pmd(walk, start, end, hmm_pfns,\n\t\t\t\t\t\t pmd);\n\n\tif (pmd_trans_huge(pmd)) {\n\t\t/*\n\t\t * No need to take pmd_lock here, even if some other thread\n\t\t * is splitting the huge pmd we will get that event through\n\t\t * mmu_notifier callback.\n\t\t *\n\t\t * So just read pmd value and check again it's a transparent\n\t\t * huge or device mapping one and compute corresponding pfn\n\t\t * values.\n\t\t */\n\t\tpmd = pmdp_get_lockless(pmdp);\n\t\tif (!pmd_trans_huge(pmd))\n\t\t\tgoto again;\n\n\t\treturn hmm_vma_handle_pmd(walk, addr, end, hmm_pfns, pmd);\n\t}\n\n\t/*\n\t * We have handled all the valid cases above ie either none, migration,\n\t * huge or transparent huge. At this point either it is a valid pmd\n\t * entry pointing to pte directory or it is a bad pmd that will not\n\t * recover.\n\t */\n\tif (pmd_bad(pmd)) {\n\t\tif (hmm_range_need_fault(hmm_vma_walk, hmm_pfns, npages, 0))\n\t\t\treturn -EFAULT;\n\t\treturn hmm_pfns_fill(start, end, range, HMM_PFN_ERROR);\n\t}\n\n\tptep = pte_offset_map(pmdp, addr);\n\tif (!ptep)\n\t\tgoto again;\n\tfor (; addr < end; addr += PAGE_SIZE, ptep++, hmm_pfns++) {\n\t\tint r;\n\n\t\tr = hmm_vma_handle_pte(walk, addr, end, pmdp, ptep, hmm_pfns);\n\t\tif (r) {\n\t\t\t/* hmm_vma_handle_pte() did pte_unmap() */\n\t\t\treturn r;\n\t\t}\n\t}\n\tpte_unmap(ptep - 1);\n\treturn 0;\n}\n\n#if defined(CONFIG_HAVE_ARCH_TRANSPARENT_HUGEPAGE_PUD)\nstatic inline unsigned long pud_to_hmm_pfn_flags(struct hmm_range *range,\n\t\t\t\t\t\t pud_t pud)\n{\n\tif (!pud_present(pud))\n\t\treturn 0;\n\treturn (pud_write(pud) ? (HMM_PFN_VALID | HMM_PFN_WRITE) :\n\t\t\t\t HMM_PFN_VALID) |\n\t       hmm_pfn_flags_order(PUD_SHIFT - PAGE_SHIFT);\n}\n\nstatic int hmm_vma_walk_pud(pud_t *pudp, unsigned long start, unsigned long end,\n\t\tstruct mm_walk *walk)\n{\n\tstruct hmm_vma_walk *hmm_vma_walk = walk->private;\n\tstruct hmm_range *range = hmm_vma_walk->range;\n\tunsigned long addr = start;\n\tpud_t pud;\n\tspinlock_t *ptl = pud_trans_huge_lock(pudp, walk->vma);\n\n\tif (!ptl)\n\t\treturn 0;\n\n\t/* Normally we don't want to split the huge page */\n\twalk->action = ACTION_CONTINUE;\n\n\tpud = pudp_get(pudp);\n\tif (!pud_present(pud)) {\n\t\tspin_unlock(ptl);\n\t\treturn hmm_vma_walk_hole(start, end, -1, walk);\n\t}\n\n\tif (pud_leaf(pud)) {\n\t\tunsigned long i, npages, pfn;\n\t\tunsigned int required_fault;\n\t\tunsigned long *hmm_pfns;\n\t\tunsigned long cpu_flags;\n\n\t\ti = (addr - range->start) >> PAGE_SHIFT;\n\t\tnpages = (end - addr) >> PAGE_SHIFT;\n\t\thmm_pfns = &range->hmm_pfns[i];\n\n\t\tcpu_flags = pud_to_hmm_pfn_flags(range, pud);\n\t\trequired_fault = hmm_range_need_fault(hmm_vma_walk, hmm_pfns,\n\t\t\t\t\t\t      npages, cpu_flags);\n\t\tif (required_fault) {\n\t\t\tspin_unlock(ptl);\n\t\t\treturn hmm_vma_fault(addr, end, required_fault, walk);\n\t\t}\n\n\t\tpfn = pud_pfn(pud) + ((addr & ~PUD_MASK) >> PAGE_SHIFT);\n\t\tfor (i = 0; i < npages; ++i, ++pfn) {\n\t\t\thmm_pfns[i] &= HMM_PFN_INOUT_FLAGS;\n\t\t\thmm_pfns[i] |= pfn | cpu_flags;\n\t\t}\n\t\tgoto out_unlock;\n\t}\n\n\t/* Ask for the PUD to be split */\n\twalk->action = ACTION_SUBTREE;\n\nout_unlock:\n\tspin_unlock(ptl);\n\treturn 0;\n}\n#else\n#define hmm_vma_walk_pud\tNULL\n#endif\n\n#ifdef CONFIG_HUGETLB_PAGE\nstatic int hmm_vma_walk_hugetlb_entry(pte_t *pte, unsigned long hmask,\n\t\t\t\t      unsigned long start, unsigned long end,\n\t\t\t\t      struct mm_walk *walk)\n{\n\tunsigned long addr = start, i, pfn;\n\tstruct hmm_vma_walk *hmm_vma_walk = walk->private;\n\tstruct hmm_range *range = hmm_vma_walk->range;\n\tstruct vm_area_struct *vma = walk->vma;\n\tunsigned int required_fault;\n\tunsigned long pfn_req_flags;\n\tunsigned long cpu_flags;\n\tspinlock_t *ptl;\n\tpte_t entry;\n\n\tptl = huge_pte_lock(hstate_vma(vma), walk->mm, pte);\n\tentry = huge_ptep_get(walk->mm, addr, pte);\n\n\ti = (start - range->start) >> PAGE_SHIFT;\n\tpfn_req_flags = range->hmm_pfns[i];\n\tcpu_flags = pte_to_hmm_pfn_flags(range, entry) |\n\t\t    hmm_pfn_flags_order(huge_page_order(hstate_vma(vma)));\n\trequired_fault =\n\t\thmm_pte_need_fault(hmm_vma_walk, pfn_req_flags, cpu_flags);\n\tif (required_fault) {\n\t\tint ret;\n\n\t\tspin_unlock(ptl);\n\t\thugetlb_vma_unlock_read(vma);\n\t\t/*\n\t\t * Avoid deadlock: drop the vma lock before calling\n\t\t * hmm_vma_fault(), which will itself potentially take and\n\t\t * drop the vma lock. This is also correct from a\n\t\t * protection point of view, because there is no further\n\t\t * use here of either pte or ptl after dropping the vma\n\t\t * lock.\n\t\t */\n\t\tret = hmm_vma_fault(addr, end, required_fault, walk);\n\t\thugetlb_vma_lock_read(vma);\n\t\treturn ret;\n\t}\n\n\tpfn = pte_pfn(entry) + ((start & ~hmask) >> PAGE_SHIFT);\n\tfor (; addr < 