    "content": "{"content":"{\n\tdebugfs_create_file_unsafe(\"fault_around_bytes\", 0644, NULL, NULL,\n\t\t\t\t   &fault_around_bytes_fops);\n\treturn 0;\n}\nlate_initcall(fault_around_debugfs);\n#endif\n\n/*\n * do_fault_around() tries to map few pages around the fault address. The hope\n * is that the pages will be needed soon and this will lower the number of\n * faults to handle.\n *\n * It uses vm_ops->map_pages() to map the pages, which skips the page if it's\n * not ready to be mapped: not up-to-date, locked, etc.\n *\n * This function doesn't cross VMA or page table boundaries, in order to call\n * map_pages() and acquire a PTE lock only once.\n *\n * fault_around_pages defines how many pages we'll try to map.\n * do_fault_around() expects it to be set to a power of two less than or equal\n * to PTRS_PER_PTE.\n *\n * The virtual address of the area that we map is naturally aligned to\n * fault_around_pages * PAGE_SIZE rounded down to the machine page size\n * (and therefore to page order).  This way it's easier to guarantee\n * that we don't cross page table boundaries.\n */\nstatic vm_fault_t do_fault_around(struct vm_fault *vmf)\n{\n\tpgoff_t nr_pages = READ_ONCE(fault_around_pages);\n\tpgoff_t pte_off = pte_index(vmf->address);\n\t/* The page offset of vmf->address within the VMA. */\n\tpgoff_t vma_off = vmf->pgoff - vmf->vma->vm_pgoff;\n\tpgoff_t from_pte, to_pte;\n\tvm_fault_t ret;\n\n\t/* The PTE offset of the start address, clamped to the VMA. */\n\tfrom_pte = max(ALIGN_DOWN(pte_off, nr_pages),\n\t\t       pte_off - min(pte_off, vma_off));\n\n\t/* The PTE offset of the end address, clamped to the VMA and PTE. */\n\tto_pte = min3(from_pte + nr_pages, (pgoff_t)PTRS_PER_PTE,\n\t\t      pte_off + vma_pages(vmf->vma) - vma_off) - 1;\n\n\tif (pmd_none(*vmf->pmd)) {\n\t\tvmf->prealloc_pte = pte_alloc_one(vmf->vma->vm_mm);\n\t\tif (!vmf->prealloc_pte)\n\t\t\treturn VM_FAULT_OOM;\n\t}\n\n\trcu_read_lock();\n\tret = vmf->vma->vm_ops->map_pages(vmf,\n\t\t\tvmf->pgoff + from_pte - pte_off,\n\t\t\tvmf->pgoff + to_pte - pte_off);\n\trcu_read_unlock();\n\n\treturn ret;\n}\n\n/* Return true if we should do read fault-around, false otherwise */\nstatic inline bool should_fault_around(struct vm_fault *vmf)\n{\n\t/* No ->map_pages?  No way to fault around... */\n\tif (!vmf->vma->vm_ops->map_pages)\n\t\treturn false;\n\n\tif (uffd_disable_fault_around(vmf->vma))\n\t\treturn false;\n\n\t/* A single page implies no faulting 'around' at all. */\n\treturn fault_around_pages > 1;\n}\n\nstatic vm_fault_t do_read_fault(struct vm_fault *vmf)\n{\n\tvm_fault_t ret = 0;\n\tstruct folio *folio;\n\n\t/*\n\t * Let's call ->map_pages() first and use ->fault() as fallback\n\t * if page by the offset is not ready to be mapped (cold cache or\n\t * something).\n\t */\n\tif (should_fault_around(vmf)) {\n\t\tret = do_fault_around(vmf);\n\t\tif (ret)\n\t\t\treturn ret;\n\t}\n\n\tret = vmf_can_call_fault(vmf);\n\tif (ret)\n\t\treturn ret;\n\n\tret = __do_fault(vmf);\n\tif (unlikely(ret & (VM_FAULT_ERROR | VM_FAULT_NOPAGE | VM_FAULT_RETRY)))\n\t\treturn ret;\n\n\tret |= finish_fault(vmf);\n\tfolio = page_folio(vmf->page);\n\tfolio_unlock(folio);\n\tif (unlikely(ret & (VM_FAULT_ERROR | VM_FAULT_NOPAGE | VM_FAULT_RETRY)))\n\t\tfolio_put(folio);\n\treturn ret;\n}\n\nstatic vm_fault_t do_cow_fault(struct vm_fault *vmf)\n{\n\tstruct vm_area_struct *vma = vmf->vma;\n\tstruct folio *folio;\n\tvm_fault_t ret;\n\n\tret = vmf_can_call_fault(vmf);\n\tif (!ret)\n\t\tret = vmf_anon_prepare(vmf);\n\tif (ret)\n\t\treturn ret;\n\n\tfolio = folio_prealloc(vma->vm_mm, vma, vmf->address, false);\n\tif (!folio)\n\t\treturn VM_FAULT_OOM;\n\n\tvmf->cow_page = &folio->page;\n\n\tret = __do_fault(vmf);\n\tif (unlikely(ret & (VM_FAULT_ERROR | VM_FAULT_NOPAGE | VM_FAULT_RETRY)))\n\t\tgoto uncharge_out;\n\tif (ret & VM_FAULT_DONE_COW)\n\t\treturn ret;\n\n\tif (copy_mc_user_highpage(vmf->cow_page, vmf->page, vmf->address, vma)) {\n\t\tret = VM_FAULT_HWPOISON;\n\t\tgoto unlock;\n\t}\n\t__folio_mark_uptodate(folio);\n\n\tret |= finish_fault(vmf);\nunlock:\n\tunlock_page(vmf->page);\n\tput_page(vmf->page);\n\tif (unlikely(ret & (VM_FAULT_ERROR | VM_FAULT_NOPAGE | VM_FAULT_RETRY)))\n\t\tgoto uncharge_out;\n\treturn ret;\nuncharge_out:\n\tfolio_put(folio);\n\treturn ret;\n}\n\nstatic vm_fault_t do_shared_fault(struct vm_fault *vmf)\n{\n\tstruct vm_area_struct *vma = vmf->vma;\n\tvm_fault_t ret, tmp;\n\tstruct folio *folio;\n\n\tret = vmf_can_call_fault(vmf);\n\tif (ret)\n\t\treturn ret;\n\n\tret = __do_fault(vmf);\n\tif (unlikely(ret & (VM_FAULT_ERROR | VM_FAULT_NOPAGE | VM_FAULT_RETRY)))\n\t\treturn ret;\n\n\tfolio = page_folio(vmf->page);\n\n\t/*\n\t * Check if the backing address space wants to know that the page is\n\t * about to become writable\n\t */\n\tif (vma->vm_ops->page_mkwrite) {\n\t\tfolio_unlock(folio);\n\t\ttmp = do_page_mkwrite(vmf, folio);\n\t\tif (unlikely(!tmp ||\n\t\t\t\t(tmp & (VM_FAULT_ERROR | VM_FAULT_NOPAGE)))) {\n\t\t\tfolio_put(folio);\n\t\t\treturn tmp;\n\t\t}\n\t}\n\n\tret |= finish_fault(vmf);\n\tif (unlikely(ret & (VM_FAULT_ERROR | VM_FAULT_NOPAGE |\n\t\t\t\t\tVM_FAULT_RETRY))) {\n\t\tfolio_unlock(folio);\n\t\tfolio_put(folio);\n\t\treturn ret;\n\t}\n\n\tret |= fault_dirty_shared_page(vmf);\n\treturn ret;\n}\n\n/*\n * We enter with non-exclusive mmap_lock (to exclude vma changes,\n * but allow concurrent faults).\n * The mmap_lock may have been released depending on flags and our\n * return value.  See filemap_fault() and __folio_lock_or_retry().\n * If mmap_lock is released, vma may become invalid (for example\n * by other thread calling munmap()).\n */\nstatic vm_fault_t do_fault(struct vm_fault *vmf)\n{\n\tstruct vm_area_struct *vma = vmf->vma;\n\tstruct mm_struct *vm_mm = vma->vm_mm;\n\tvm_fault_t ret;\n\n\t/*\n\t * The VMA was not fully populated on mmap() or missing VM_DONTEXPAND\n\t */\n\tif (!vma->vm_ops->fault) {\n\t\tvmf->pte = pte_offset_map_lock(vmf->vma->vm_mm, vmf->pmd,\n\t\t\t\t\t       vmf->address, &vmf->ptl);\n\t\tif (unlikely(!vmf->pte))\n\t\t\tret = VM_FAULT_SIGBUS;\n\t\telse {\n\t\t\t/*\n\t\t\t * Make sure this is not a temporary clearing of pte\n\t\t\t * by holding ptl and checking again. A R/M/W update\n\t\t\t * of pte involves: take ptl, clearing the pte so that\n\t\t\t * we don't have concurrent modification by hardware\n\t\t\t * followed by an update.\n\t\t\t */\n\t\t\tif (unlikely(pte_none(ptep_get(vmf->pte))))\n\t\t\t\tret = VM_FAULT_SIGBUS;\n\t\t\telse\n\t\t\t\tret = VM_FAULT_NOPAGE;\n\n\t\t\tpte_unmap_unlock(vmf->pte, vmf->ptl);\n\t\t}\n\t} else if (!(vmf->flags & FAULT_FLAG_WRITE))\n\t\tret = do_read_fault(vmf);\n\telse if (!(vma->vm_flags & VM_SHARED))\n\t\tret = do_cow_fault(vmf);\n\telse\n\t\tret = do_shared_fault(vmf);\n\n\t/* preallocated pagetable is unused: free it */\n\tif (vmf->prealloc_pte) {\n\t\tpte_free(vm_mm, vmf->prealloc_pte);\n\t\tvmf->prealloc_pte = NULL;\n\t}\n\treturn ret;\n}\n\nint numa_migrate_check(struct folio *folio, struct vm_fault *vmf,\n\t\t      unsigned long addr, int *flags,\n\t\t      bool writable, int *last_cpupid)\n{\n\tstruct vm_area_struct *vma = vmf->vma;\n\n\t/*\n\t * Avoid grouping on RO pages in general. RO pages shouldn't hurt as\n\t * much anyway since they can be in shared cache state. This misses\n\t * the case where a mapping is writable but the process never writes\n\t * to it but pte_write gets cleared during protection updates and\n\t * pte_dirty has unpredictable behaviour between PTE scan updates,\n\t * background writeback, dirty balancing and application behaviour.\n\t */\n\tif (!writable)\n\t\t*flags |= TNF_NO_GROUP;\n\n\t/*\n\t * Flag if the folio is shared between multiple address spaces. This\n\t * is later used when determining whether to group tasks together\n\t */\n\tif (folio_maybe_mapped_shared(folio) && (vma->vm_flags & VM_SHARED))\n\t\t*flags |= TNF_SHARED;\n\t/*\n\t * For memory tiering mode, cpupid of slow memory page is used\n\t * to record page access time.  So use default value.\n\t */\n\tif (folio_use_access_time(folio))\n\t\t*last_cpupid = (-1 & LAST_CPUPID_MASK);\n\telse\n\t\t*last_cpupid = folio_last_cpupid(folio);\n\n\t/* Record the current PID accessing VMA */\n\tvma_set_access_pid_bit(vma);\n\n\tcount_vm_numa_event(NUMA_HINT_FAULTS);\n#ifdef CONFIG_NUMA_BALANCING\n\tcount_memcg_folio_events(folio, NUMA_HINT_FAULTS, 1);\n#endif\n\tif (folio_nid(folio) == numa_node_id()) {\n\t\tcount_vm_numa_event(NUMA_HINT_FAULTS_LOCAL);\n\t\t*flags |= TNF_FAULT_LOCAL;\n\t}\n\n\treturn mpol_misplaced(folio, vmf, addr);\n}\n\nstatic void numa_rebuild_single_mapping(struct vm_fault *vmf, struct vm_area_struct *vma,\n\t\t\t\t\tunsigned long fault_addr, pte_t *fault_pte,\n\t\t\t\t\tbool writable)\n{\n\tpte_t pte, old_pte;\n\n\told_pte = ptep_modify_prot_start(vma, fault_addr, fault_pte);\n\tpte = pte_modify(old_pte, vma->vm_page_prot);\n\tpte = pte_mkyoung(pte);\n\tif (writable)\n\t\tpte = pte_mkwrite(pte, vma);\n\tptep_modify_prot_commit(vma, fault_addr, fault_pte, old_pte, pte);\n\tupdate_mmu_cache_range(vmf, vma, fault_addr, fault_pte, 1);\n}\n\nstatic void numa_rebuild_large_mapping(struct vm_fault *vmf, struct vm_area_struct *vma,\n\t\t\t\t       struct folio *folio, pte_t fault_pte,\n\t\t\t\t       bool ignore_writable, bool pte_write_upgrade)\n{\n\tint nr = pte_pfn(fault_pte) - folio_pfn(folio);\n\tunsigned long start, end, addr = vmf->address;\n\tunsigned long addr_start = addr - (nr << PAGE_SHIFT);\n\tunsigned long pt_start = ALIGN_DOWN(addr, PMD_SIZE);\n\tpte_t *start_ptep;\n\n\t/* Stay within the VMA and within the page table. */\n\tstart = max3(addr_start, pt_start, vma->vm_start);\n\tend = min3(addr_start + folio_size(folio), pt_start + PMD_SIZE,\n\t\t   vma->vm_end);\n\tstart_ptep = vmf->pte - ((addr - start) >> PAGE_SHIFT);\n\n\t/* Restore all PTEs' mapping of the large folio */\n\tfor (addr = start; addr != end; start_ptep++, addr += PAGE_SIZE) {\n\t\tpte_t ptent = ptep_get(start_ptep);\n\t\tbool writable = false;\n\n\t\tif (!pte_present(ptent) || !pte_protnone(ptent))\n\t\t\tcontinue;\n\n\t\tif (pfn_folio(pte_pfn(ptent)) != folio)\n\t\t\tcontinue;\n\n\t\tif (!ignore_writable) {\n\t\t\tptent = pte_modify(ptent, vma->vm_page_prot);\n\t\t\twritable = pte_write(ptent);\n\t\t\tif (!writable && pte_write_upgrade &&\n\t\t\t    can_change_pte_writable(vma, addr, ptent))\n\t\t\t\twritable = true;\n\t\t}\n\n\t\tnuma_rebuild_single_mapping(vmf, vma, addr, start_ptep, writable);\n\t}\n}\n\nstatic vm_fault_t do_numa_page(struct vm_fault *vmf)\n{\n\tstruct vm_area_struct *vma = vmf->vma;\n\tstruct folio *folio = NULL;\n\tint nid = NUMA_NO_NODE;\n\tbool writable = false, ignore_writable = false;\n\tbool pte_write_upgrade = vma_wants_manual_pte_write_upgrade(vma);\n\tint last_cpupid;\n\tint target_nid;\n\tpte_t pte, old_pte;\n\tint flags = 0, nr_pages;\n\n\t/*\n\t * The pte cannot be used safely until we verify, while holding the page\n\t * table lock, that its contents have not changed during fault handling.\n\t */\n\tspin_lock(vmf->ptl);\n\t/* Read the live PTE from the page tables: */\n\told_pte = ptep_get(vmf->pte);\n\n\tif (unlikely(!pte_same(old_pte, vmf->orig_pte))) {\n\t\tpte_unmap_unlock(vmf->pte, vmf->ptl);\n\t\treturn 0;\n\t}\n\n\tpte = pte_modify(old_pte, vma->vm_page_prot);\n\n\t/*\n\t * Detect now whether the PTE could be writable; this information\n\t * is only valid while holding the PT lock.\n\t */\n\twritable = pte_write(pte);\n\tif (!writable && pte_write_upgrade &&\n\t    can_change_pte_writable(vma, vmf->address, pte))\n\t\twritable = true;\n\n\tfolio = vm_normal_folio(vma, vmf->address, pte);\n\tif (!folio || folio_is_zone_device(folio))\n\t\tgoto out_map;\n\n\tnid = folio_nid(folio);\n\tnr_pages = folio_nr_pages(folio);\n\n\ttarget_nid = numa_migrate_check(folio, vmf, vmf->address, &flags,\n\t\t\t\t\twritable, &last_cpupid);\n\tif (target_nid == NUMA_NO_NODE)\n\t\tgoto out_map;\n\tif (migrate_misplaced_folio_prepare(folio, vma, target_nid)) {\n\t\tflags |= TNF_MIGRATE_FAIL;\n\t\tgoto out_map;\n\t}\n\t/* The folio is isolated and isolation code holds a folio reference. */\n\tpte_unmap_unlock(vmf->pte, vmf->ptl);\n\twritable = false;\n\tignore_writable = true;\n\n\t/* Migrate to the requested node */\n\n... [Diff truncated. Dropped 989 lines] ...\n\n\n\t/* Avoid triggering the temporary warning in __get_user_pages */\n\tif (!vma_lookup(mm, addr)) {\n\t\terr = -EFAULT;\n\t\tgoto out;\n\t}\n\n\twhile (len) {\n\t\tint bytes, offset, retval;\n\t\tvoid *maddr;\n\t\tstruct folio *folio;\n\t\tstruct page *page;\n\t\tstruct vm_area_struct *vma = NULL;\n\n\t\tpage = get_user_page_vma_remote(mm, addr, gup_flags, &vma);\n\t\tif (IS_ERR(page)) {\n\t\t\t/*\n\t\t\t * Treat as a total failure for now until we decide how\n\t\t\t * to handle the CONFIG_HAVE_IOREMAP_PROT case and\n\t\t\t * stack expansion.\n\t\t\t */\n\t\t\t*(char *)buf = '\\0';\n\t\t\terr = -EFAULT;\n\t\t\tgoto out;\n\t\t}\n\n\t\tfolio = page_folio(page);\n\t\tbytes = len;\n\t\toffset = addr & (PAGE_SIZE - 1);\n\t\tif (bytes > PAGE_SIZE - offset)\n\t\t\tbytes = PAGE_SIZE - offset;\n\n\t\tmaddr = kmap_local_folio(folio, folio_page_idx(folio, page) * PAGE_SIZE);\n\t\tretval = strscpy(buf, maddr + offset, bytes);\n\t\tif (retval >= 0) {\n\t\t\t/* Found the end of the string */\n\t\t\tbuf += retval;\n\t\t\tfolio_release_kmap(folio, maddr);\n\t\t\tbreak;\n\t\t}\n\n\t\tbuf += bytes - 1;\n\t\t/*\n\t\t * Because strscpy always NUL terminates we need to\n\t\t * copy the last byte in the page if we are going to\n\t\t * load more pages\n\t\t */\n\t\tif (bytes != len) {\n\t\t\taddr += bytes - 1;\n\t\t\tcopy_from_user_page(vma, page, addr, buf, maddr + (PAGE_SIZE - 1), 1);\n\t\t\tbuf += 1;\n\t\t\taddr += 1;\n\t\t}\n\t\tlen -= bytes;\n\n\t\tfolio_release_kmap(folio, maddr);\n\t}\n\nout:\n\tmmap_read_unlock(mm);\n\tif (err)\n\t\treturn err;\n\treturn buf - old_buf;\n}\n\n/**\n * copy_remote_vm_str - copy a string from another process's address space.\n * @tsk:\tthe task of the target address space\n * @addr:\tstart addres